<h1>Project Board</h1>

@if (isLoading)
{
    <p><em>Loading tasks...</em></p>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}
else
{
    <!-- Stats Bar -->
    <div class="stats-bar">
        <span class="stat-item"><strong>Total:</strong> @filteredTasks.Count</span>
        <span class="stat-item"><strong>To Do:</strong> @GetColumnTasks("To Do").Count</span>
        <span class="stat-item"><strong>In Progress:</strong> @GetColumnTasks("In Progress").Count</span>
        <span class="stat-item"><strong>Done:</strong> @GetColumnTasks("Done").Count</span>
        <span class="stat-item stat-overdue"><strong>Overdue:</strong> @filteredTasks.Count(t => t.DueDate < DateTime.Today)</span>
    </div>

    <!-- Search Bar -->
    <div class="search-bar">
        <input type="text" placeholder="Search tasks by title..." @bind="searchText" @bind:event="oninput" class="form-control" />
    </div>

    <!-- Kanban Columns -->
    <div class="kanban-board">
        @foreach (var column in columns)
        {
            var columnTasks = GetColumnTasks(column);
            <div class="kanban-column">
                <div class="column-header">
                    <h3>@column <span class="badge">@columnTasks.Count</span></h3>
                </div>
                <div class="column-body">
                    @foreach (var task in columnTasks)
                    {
                        <div class="task-card">
                            <div class="task-title">@task.Title</div>
                            <div class="task-assignee">@task.Assignee</div>
                            <span class="priority-badge priority-@task.Priority.ToLower()">@task.Priority</span>
                            <div class="task-due">@task.DueDate.ToString("MMM dd")</div>
                            <div class="task-actions">
                                @if (GetColumnIndex(column) > 0)
                                {
                                    <button class="btn btn-sm btn-outline-secondary" @onclick="() => MoveTask(task, -1)" disabled="@isMoving">← Move Left</button>
                                }
                                @if (GetColumnIndex(column) < columns.Length - 1)
                                {
                                    <button class="btn btn-sm btn-outline-secondary" @onclick="() => MoveTask(task, 1)" disabled="@isMoving">Move Right →</button>
                                }
                            </div>
                        </div>
                    }
                </div>
                @if (addingToColumn == column)
                {
                    <div class="add-task-form">
                        <input type="text" placeholder="Title" @bind="newTitle" class="form-control" />
                        <input type="text" placeholder="Assignee" @bind="newAssignee" class="form-control" />
                        <select @bind="newPriority" class="form-control">
                            <option value="High">High</option>
                            <option value="Medium">Medium</option>
                            <option value="Low">Low</option>
                        </select>
                        <input type="date" @bind="newDueDate" class="form-control" />
                        <div class="form-buttons">
                            <button class="btn btn-primary btn-sm" @onclick="SaveNewTask" disabled="@isSaving">Save</button>
                            <button class="btn btn-secondary btn-sm" @onclick="CancelAdd">Cancel</button>
                        </div>
                    </div>
                }
                else
                {
                    <button class="btn btn-outline-primary btn-sm add-task-btn" @onclick="() => StartAdd(column)">+ Add Task</button>
                }
            </div>
        }
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = string.Empty;
    private bool isLoading = true;
    private bool isMoving;
    private bool isSaving;
    private string? errorMessage;

    private string[] columns = { "To Do", "In Progress", "Done" };

    // Add task form state
    private string? addingToColumn;
    private string newTitle = string.Empty;
    private string newAssignee = string.Empty;
    private string newPriority = "Medium";
    private DateTime newDueDate = DateTime.Today;

    private List<TaskItem> filteredTasks => string.IsNullOrWhiteSpace(searchText)
        ? allTasks
        : allTasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)).ToList();

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetColumnTasks(string status) =>
        filteredTasks.Where(t => t.Status == status).ToList();

    private int GetColumnIndex(string column) => Array.IndexOf(columns, column);

    private async Task MoveTask(TaskItem task, int direction)
    {
        var currentIndex = GetColumnIndex(task.Status);
        var newIndex = currentIndex + direction;
        if (newIndex < 0 || newIndex >= columns.Length) return;

        isMoving = true;
        try
        {
            var newStatus = columns[newIndex];
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            // Update local state
            var index = allTasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
            {
                allTasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
        finally
        {
            isMoving = false;
        }
    }

    private void StartAdd(string column)
    {
        addingToColumn = column;
        newTitle = string.Empty;
        newAssignee = string.Empty;
        newPriority = "Medium";
        newDueDate = DateTime.Today;
    }

    private void CancelAdd()
    {
        addingToColumn = null;
    }

    private async Task SaveNewTask()
    {
        if (string.IsNullOrWhiteSpace(newTitle) || addingToColumn is null) return;

        isSaving = true;
        try
        {
            var created = await TaskService.CreateTaskAsync(newTitle, newAssignee, newPriority, newDueDate);
            allTasks.Add(created);
            addingToColumn = null;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
        finally
        {
            isSaving = false;
        }
    }
}

